1663	        LOG_DBG("Using specialized template: Kimi K2 Thinking\n");
1664	        return common_chat_params_init_kimi_k2(tmpl, params);
1665	    }
1666	
1667	    // LFM2 format detection: template uses <|tool_list_start|>[...]<|tool_list_end|> around the tool list
1668	    // and <|tool_call_start|>[...]<|tool_call_end|> around each tool call
1669	    if (src.find("<|tool_list_start|>") != std::string::npos &&
1670	        src.find("<|tool_list_end|>") != std::string::npos) {
1671	        LOG_DBG("Using specialized template: LFM2\n");
1672	        return common_chat_params_init_lfm2(tmpl, params);
1673	    }
1674	
1675	    // LFM2.5 format detection: template uses plain "List of tools: [...]" with no special tokens
1676	    if (src.find("List of tools: [") != std::string::npos &&
1677	        src.find("<|tool_list_start|>") == std::string::npos) {
1678	        LOG_DBG("Using specialized template: LFM2.5\n");
1679	        return common_chat_params_init_lfm2_5(tmpl, params);
1680	    }
1681	
1682	    // GigaChatV3 format detection
1683	    if (src.find("<|role_sep|>") != std::string::npos &&
1684	        src.find("<|message_sep|>") != std::string::npos &&
