401	    std::vector<common_chat_tool> result;
402	
403	    try {
404	        if (!tools.is_null()) {
405	            if (!tools.is_array()) {
406	                throw std::invalid_argument("Expected 'tools' to be an array, got " + tools.dump());
407	            }
408	            for (const auto & tool : tools) {
409	                if (!tool.contains("type")) {
410	                    throw std::invalid_argument("Missing tool type: " + tool.dump());
411	                }
412	                const auto & type = tool.at("type");
413	                if (!type.is_string() || type != "function") {
414	                    throw std::invalid_argument("Unsupported tool type: " + tool.dump());
415	                }
416	                if (!tool.contains("function")) {
417	                    throw std::invalid_argument("Missing tool function: " + tool.dump());
418	                }
